        }
    }
    classStyle {
        fillcolor: #c0f0e0
        borderStyle: solid
        borderColor: #000000
        labelStyle {
            fontColor: #000000
            fontStyle: bold
        }
    }
}

class Duck {
    +public abstract void display()
    +void quack()
    +void swim()
    +void fly()
}

class WildDuck {
    +void display()
}

class PekingDuck {
    +void display()
    +void fly()
}

class ToyDuck {
    +void display()
    +void quack()
    +void swim()
    +void fly()
}

Duck <|-- WildDuck
Duck <|-- PekingDuck
Duck <|-- ToyDuck

@enduml
